css:
.signatures {
  margin-top: 34px;
  page-break-inside: avoid;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
}

.signatures td {
  width: 50%;
  padding: 18px 24px 14px 0;
  border: none;
  vertical-align: bottom;
}

.signatures td:nth-child(even) {
  padding-right: 0;
}

.signature-space {
  height: 34px;
}

.signature-line {
  width: 100%;
  margin-bottom: 5px;
  border-top: 1px solid #333;
}

.signatures p {
  margin: 0;
  font-size: 9pt;
}

@page {
  margin: 20mm 15mm 25mm 15mm; /* top right bottom left */
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
